// Maior círculo que um ocultista pode lançar no NEX dado
export function circuloMaximo(nex) {
  if (nex >= 85) return 4
  if (nex >= 55) return 3
  if (nex >= 25) return 2
  return 1
}

// Lista achatada de rituais disponíveis até o NEX dado (com elemento/círculo/custo)
export function getRituaisDisponiveis(nex, { incluirMedoTrilha = false } = {}) {
  const max = circuloMaximo(nex)
  const out = []
  for (const el of ELEMENTOS) {
    for (let c = 1; c <= max; c++) {
      for (const r of RITUAIS[el]?.[c] ?? []) {
        if (r.trilhaLock && !incluirMedoTrilha) continue
        out.push({ ...r, elemento: el, circulo: c, custo: CUSTO_POR_CIRCULO[c] })
      }
    }
  }
  return out
}
